<?php
require_once dirname(__DIR__) . '/includes/functions.php';
employeePortalGuard();$user=currentUser();$pdo=getDB();$employee=employeeForCurrentUser($pdo,$user);if(!$employee){siteHeader('My Attendance','login');echo '<div class="alert alert-warning">No employee profile is linked to your email.</div>';siteFooter();exit;}
$rows=$pdo->prepare('SELECT a.*,s.shift_code,s.shift_name FROM '.table('attendance_records').' a LEFT JOIN '.table('employee_shift_assignments').' sa ON sa.employee_id=a.employee_id AND sa.work_date=a.work_date LEFT JOIN '.table('employee_shift_templates').' s ON s.id=sa.employee_shift_template_id WHERE a.employee_id=? ORDER BY a.work_date DESC LIMIT 90');$rows->execute([(int)$employee['id']]);$rows=$rows->fetchAll();
$shifts=$pdo->prepare('SELECT a.*,s.shift_code,s.shift_name,s.start_time,s.end_time FROM '.table('employee_shift_assignments').' a LEFT JOIN '.table('employee_shift_templates').' s ON s.id=a.employee_shift_template_id WHERE a.employee_id=? AND a.work_date>=CURDATE() ORDER BY a.work_date ASC LIMIT 30');$shifts->execute([(int)$employee['id']]);$shifts=$shifts->fetchAll();
siteHeader('My Attendance','login');
?>
<h1 class="mb-4">My Attendance</h1><div class="row g-4"><div class="col-lg-7"><div class="table-card table-responsive"><h2 class="h5">Attendance Records</h2><table class="table"><thead><tr><th>Date</th><th>In</th><th>Out</th><th>Hours</th><th>OT</th><th>Status</th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><?php echo esc($r['work_date']); ?></td><td><?php echo esc($r['check_in']); ?></td><td><?php echo esc($r['check_out']); ?></td><td><?php echo number_format((float)$r['regular_hours'],2); ?></td><td><?php echo number_format((float)$r['overtime_hours'],2); ?></td><td><span class="badge bg-<?php echo esc(statusTone($r['status'])); ?>"><?php echo esc($r['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div><div class="col-lg-5"><div class="table-card table-responsive"><h2 class="h5">Upcoming Shifts</h2><table class="table"><thead><tr><th>Date</th><th>Shift</th><th>Time</th></tr></thead><tbody><?php foreach($shifts as $s): ?><tr><td><?php echo esc($s['work_date']); ?></td><td><?php echo esc($s['shift_code'].' · '.$s['shift_name']); ?></td><td><?php echo esc($s['start_time'].' - '.$s['end_time']); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php siteFooter(); ?>